};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Stethoscope, 
  Pill, 
  Activity, 
  Brain, 
  Plus, 
  FileText, 
  Camera, 
  ChevronRight, 
  Loader2, 
  CheckCircle2, 
  AlertTriangle, 
  XCircle,
  Search,
  User,
  Calendar,
  Layers,
  Trash2
} from 'lucide-react';
import { PatientInfo, MedicalFile, AppStep, AnalysisResult } from './types';
import { performMultiAIAnalysis, webFetch } from './services/putterAdapter';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(1);
  const [patient, setPatient] = useState<PatientInfo>({ name: '', age: '', gender: '' });
  const [files, setFiles] = useState<MedicalFile[]>([]);
  const [manualMeds, setManualMeds] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [webResults, setWebResults] = useState<string[]>([]);

  // Progressive reveal triggers
  const showAge = patient.name.trim().length > 2;
  const showGender = typeof patient.age === 'number' || (patient.age !== '' && parseInt(patient.age as string) > 0);
  const showNextStep1 = patient.gender !== '';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map(f => ({
        id: Math.random().toString(36).substr(2, 9),
        file: f,
        previewUrl: URL.createObjectURL(f),
        type,
        name: f.name
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setStep(3);
    try {
      const result = await performMultiAIAnalysis(patient, files, manualMeds);
      setAnalysisResult(result);
      const searchTerms = result.diagnosis.map(d => d.issue).join(" ");
      const web = await webFetch(searchTerms);
      setWebResults(web);
    } catch (err) {
      console.error("Analysis failed", err);
      // Fallback for demo purposes if API key is missing/fails
      setAnalysisResult(MOCK_RESULT);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen text-white p-4 md:p-8 flex flex-col items-center">
      {/* Header */}
      <header className="w-full max-w-4xl flex items-center justify-between mb-8 animate-float">
        <div className="flex items-center gap-3">
          <div className="p-3 glass rounded-2xl bg-emerald-500/20">
            <Stethoscope className="w-8 h-8 text-emerald-300" />
          </div>
          <div>
            <h1 className="text-3xl font-bold tracking-tight">GenAI Doctor</h1>
            <p className="text-emerald-100 text-sm opacity-80">Next-Gen Medical Analysis</p>
          </div>
        </div>
        <div className="hidden md:flex gap-4">
          {[1, 2, 3].map((s) => (
            <div key={s} className={`flex items-center gap-2 px-4 py-2 rounded-full glass transition-all duration-500 ${step === s ? 'bg-white/20 scale-105 border-emerald-400' : 'opacity-40'}`}>
              <span className="text-sm font-bold">{s}</span>
              <span className="text-xs uppercase tracking-widest">{s === 1 ? 'Profile' : s === 2 ? 'Upload' : 'Result'}</span>
            </div>
          ))}
        </div>
      </header>

      <main className="w-full max-w-4xl">
        {step === 1 && (
          <div className="glass rounded-3xl p-8 space-y-8 animate-in slide-in-from-bottom duration-500">
            <div className="space-y-2">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <User className="text-emerald-300" /> Patient Profile
              </h2>
              <p className="text-emerald-100/60">Help us identify the medical context.</p>
            </div>

            <div className="space-y-6">
              {/* Name */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-emerald-200 ml-1">Patient Name</label>
                <input 
                  type="text"
                  placeholder="e.g. John Doe"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:ring-2 focus:ring-emerald-400 transition-all text-xl"
                  value={patient.name}
                  onChange={(e) => setPatient({...patient, name: e.target.value})}
                />
              </div>

              {/* Age - Progressive Reveal */}
              {showAge && (
                <div className="space-y-2 animate-in slide-in-from-top duration-500">
                  <label className="text-sm font-medium text-emerald-200 ml-1">Age</label>
                  <input 
                    type="number"
                    min="1"
                    max="120"
                    placeholder="e.g. 45"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:ring-2 focus:ring-emerald-400 transition-all text-xl"
                    value={patient.age}
                    onChange={(e) => setPatient({...patient, age: e.target.value === '' ? '' : parseInt(e.target.value)})}
                  />
                </div>
              )}

              {/* Gender - Progressive Reveal */}
              {showGender && (
