                  </label>
                </div>

                <div className="min-h-[120px] border-2 border-dashed border-white/20 rounded-2xl flex flex-col items-center justify-center p-4 bg-white/5 group-hover:bg-white/10 transition-all">
                  {files.filter(f => f.type === 'prescription').length === 0 ? (
                    <p className="text-emerald-100/40 text-sm text-center">Drag & drop or click + to upload medical prescriptions.</p>
                  ) : (
                    <div className="w-full space-y-2">
                      {files.filter(f => f.type === 'prescription').map(f => (
                        <div key={f.id} className="flex items-center justify-between bg-white/10 p-2 rounded-xl text-xs">
                          <span className="truncate max-w-[150px]">{f.name}</span>
                          <button onClick={() => removeFile(f.id)}><Trash2 className="w-4 h-4 text-red-400" /></button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Scan Reports Upload */}
              <div className="glass rounded-3xl p-6 space-y-4 relative group">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-bold flex items-center gap-2">
                    <Activity className="text-cyan-300" /> Scan Reports
                  </h3>
                  <label className="cursor-pointer p-2 glass rounded-full hover:bg-cyan-400/20 transition-all">
                    <Plus className="w-5 h-5 text-cyan-200" />
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'scan')} accept=".pdf,.jpg,.png" />
                  </label>
                </div>

                <div className="min-h-[120px] border-2 border-dashed border-white/20 rounded-2xl flex flex-col items-center justify-center p-4 bg-white/5 group-hover:bg-white/10 transition-all">
                  {files.filter(f => f.type === 'scan').length === 0 ? (
                    <p className="text-cyan-100/40 text-sm text-center">CBP, Sugar, X-Ray, MRI, CT Scans etc.</p>
                  ) : (
                    <div className="w-full space-y-2">
                      {files.filter(f => f.type === 'scan').map(f => (
                        <div key={f.id} className="flex items-center justify-between bg-white/10 p-2 rounded-xl text-xs">
                          <span className="truncate max-w-[150px]">{f.name}</span>
                          <button onClick={() => removeFile(f.id)}><Trash2 className="w-4 h-4 text-red-400" /></button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Manual Medications */}
            <div className="glass rounded-3xl p-6 space-y-4">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <Layers className="text-emerald-300" /> Manual Medications Entry
              </h3>
              <textarea 
