                </label>
              </div>
              <div className="flex gap-4 overflow-x-auto pb-2">
                {files.filter(f => f.type === 'tablet').map(f => (
                  <div key={f.id} className="relative w-20 h-20 flex-shrink-0">
                    <img src={f.previewUrl} className="w-full h-full object-cover rounded-xl" />
                    <button onClick={() => removeFile(f.id)} className="absolute -top-2 -right-2 bg-red-500 rounded-full p-1"><XCircle className="w-4 h-4" /></button>
                  </div>
                ))}
                {files.filter(f => f.type === 'tablet').length === 0 && (
                  <p className="text-cyan-100/40 text-sm">Upload tablet images for AI recognition.</p>
                )}
              </div>
            </div>

            <div className="flex gap-4 pt-4">
               <button 
                  onClick={() => setStep(1)}
                  className="flex-1 glass text-white font-bold py-5 rounded-2xl transition-all hover:bg-white/10"
                >
                  Back
                </button>
                <button 
                  onClick={startAnalysis}
                  className="flex-[2] bg-emerald-500 hover:bg-emerald-400 text-white font-bold py-5 rounded-2xl flex items-center justify-center gap-2 transition-all hover:scale-[1.02] active:scale-95 animate-pulse-glow"
                >
                  Run Multi-AI Diagnosis <Brain />
                </button>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8 animate-in zoom-in-95 duration-700">
            {isAnalyzing ? (
              <div className="glass rounded-3xl p-16 flex flex-col items-center justify-center space-y-6">
                <Loader2 className="w-16 h-16 text-emerald-300 animate-spin" />
                <div className="text-center space-y-2">
                  <h2 className="text-2xl font-bold animate-pulse">Analyzing Documents...</h2>
                  <p className="text-emerald-100/60 max-w-sm">Cross-verifying scan results with prescription data using GPT-5.2 and Gemini 3 pipeline.</p>
