                  <div className="grid grid-cols-1 gap-4">
                    {analysisResult.diagnosis.map((d, i) => (
                      <div key={i} className="glass rounded-2xl p-6 border-l-4 border-l-emerald-500 hover:bg-white/15 transition-all">
                        <div className="flex justify-between items-start mb-2">
                          <h4 className="text-lg font-bold text-emerald-500">✓ ISSUE: {d.issue}</h4>
                          <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${
