import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { PatientInfo, MedicalFile, AnalysisResult } from "../types";

/**
 * This service implements the 'Putter.js' framework requirements 
 * using the Vayu AGI engine (Powered by Gemini).
 */

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const performMultiAIAnalysis = async (
  patient: PatientInfo,
  files: MedicalFile[],
  manualMeds: string
): Promise<AnalysisResult> => {
  const ai = getAI();

  const parts: any[] = [
    { text: `You are Vayu AGI, a high-precision medical analysis engine. Analyze the following patient data: 
      Name: ${patient.name}, Age: ${patient.age}, Gender: ${patient.gender}. 
      Manual medication notes: ${manualMeds}. 
      Task: Perform deep analysis of the attached medical documents (prescriptions/scans). 
      Identify issues, verify dosages, and suggest evidence-based medical paths. 
      Return only JSON matching the requested schema.` }
  ];

  for (const f of files) {
    const b64 = await fileToBase64(f.file);
    parts.push({
      inlineData: {
        data: b64,
        mimeType: f.file.type || 'image/png'
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          diagnosis: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                issue: { type: Type.STRING },
                values: { type: Type.STRING },
                severity: { type: Type.STRING, enum: ['CRITICAL', 'MODERATE', 'MILD', 'NORMAL'] },
                referenceRange: { type: Type.STRING },
                assessment: { type: Type.STRING }
              },
              required: ['issue', 'values', 'severity', 'referenceRange', 'assessment']
            }
          },
          prescriptions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                dosage: { type: Type.STRING },
                frequency: { type: Type.STRING },
                verification: { type: Type.STRING, enum: ['CORRECT', 'CHECK', 'ISSUE'] },
                verificationNote: { type: Type.STRING }
              },
              required: ['name', 'dosage', 'frequency', 'verification', 'verificationNote']
            }
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              do: { type: Type.ARRAY, items: { type: Type.STRING } },
              avoid: { type: Type.ARRAY, items: { type: Type.STRING } },
              monitor: { type: Type.ARRAY, items: { type: Type.STRING } },
              consult: { type: Type.STRING }
            },
            required: ['do', 'avoid', 'monitor', 'consult']
          },
          confidenceScore: { type: Type.NUMBER }
        },
        required: ['diagnosis', 'prescriptions', 'recommendations', 'confidenceScore']
      }
    }
  });

  const resultText = response.text || '{}';
  return JSON.parse(resultText) as AnalysisResult;
};

