                        <div key={i} className="glass rounded-[25px] p-6 text-sm text-gray-400 font-medium leading-relaxed border border-white/5 hover:border-emerald-400/30 transition-all animate-in slide-in-from-right duration-500" style={{ animationDelay: `${i * 150}ms` }}>
                          <span className="text-emerald-400 font-black mr-2">VAYU_REF_0{i+1}:</span> {res}
