import React, { useState, useEffect, useRef } from 'react';
import { 
  Stethoscope, 
  Pill, 
  Activity, 
  Brain, 
  Plus, 
  FileText, 
  Camera, 
  ChevronRight, 
  Loader2, 
  CheckCircle2, 
  AlertTriangle, 
  XCircle,
  Search,
  User,
  Layers,
  Trash2,
  Check,
  X,
  Dna
} from 'lucide-react';
import { PatientInfo, MedicalFile, AppStep, AnalysisResult } from './types';
import { performMultiAIAnalysis, webFetch } from './services/putterAdapter';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(1);
  const [patient, setPatient] = useState<PatientInfo>({ name: '', age: '', gender: '' });
  const [files, setFiles] = useState<MedicalFile[]>([]);
  const [fileNotifications, setFileNotifications] = useState<Record<string, boolean>>({});
  const [tabletToast, setTabletToast] = useState(false);
  const [manualMeds, setManualMeds] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [webResults, setWebResults] = useState<string[]>([]);

  // Progressive reveal triggers
  const showAge = patient.name.trim().length > 2;
  const showGender = typeof patient.age === 'number' || (patient.age !== '' && parseInt(patient.age as string) > 0);
  const showNextStep1 = patient.gender !== '';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map(f => {
        const id = Math.random().toString(36).substr(2, 9);

        // General Notification
        setFileNotifications(prev => ({ ...prev, [id]: true }));
        setTimeout(() => {
          setFileNotifications(prev => ({ ...prev, [id]: false }));
        }, 5000);

        // Tablet specific Toast
        if (type === 'tablet') {
          setTabletToast(true);
          setTimeout(() => setTabletToast(false), 3000);
        }

        return {
          id,
          file: f,
          previewUrl: URL.createObjectURL(f),
          type,
          name: f.name
        };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
    setFileNotifications(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
  };

  const dismissNotification = (id: string) => {
    setFileNotifications(prev => ({ ...prev, [id]: false }));
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setStep(3);
    try {
      const result = await performMultiAIAnalysis(patient, files, manualMeds);
      setAnalysisResult(result);
      const searchTerms = result.diagnosis.map(d => d.issue).join(" ");
      const web = await webFetch(searchTerms);
      setWebResults(web);
    } catch (err) {
      console.error("Analysis failed", err);
      setAnalysisResult(MOCK_RESULT);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const DnaLoader = () => (
    <div className="relative w-32 h-40 flex items-center justify-center">
      {[...Array(10)].map((_, i) => (
        <React.Fragment key={i}>
          <div 
            className="dna-node" 
            style={{ 
              left: `${i * 10}%`, 
              animationDelay: `${i * 0.2}s`,
              background: '#00f3ff'
            }} 
          />
          <div 
            className="dna-node" 
            style={{ 
              left: `${i * 10}%`, 
              animationDelay: `${i * 0.2 + 1}s`,
              background: '#a855f7'
            }} 
          />
        </React.Fragment>
      ))}
      <Dna className="w-12 h-12 neon-text animate-pulse absolute opacity-50" />
    </div>
  );

  return (
    <div className="min-h-screen text-white pb-24 flex flex-col items-center">
      {/* Tablet Success Toast */}
      {tabletToast && (
        <div className="fixed top-24 z-[100] px-6 py-3 glass neon-border rounded-full flex items-center gap-3 animate-in fade-in slide-in-from-top-4 duration-500 fade-out-custom">
          <div className="bg-emerald-500/20 p-1 rounded-full">
            <Check className="w-4 h-4 text-emerald-400" />
          </div>
          <span className="text-xs font-black uppercase tracking-widest neon-text">Tablet Data Logged</span>
        </div>
      )}

      {/* Header - Enhanced Blur Glass */}
      <header className="w-full h-24 flex items-center justify-center sticky top-0 z-50 header-glass">
        <div className="w-full max-w-5xl px-8 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="p-2.5 rounded-xl bg-cyan-500/10 neon-border">
              <Brain className="w-7 h-7 neon-text" />
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight neon-text font-poppins">Vayu AGI</h1>
              <p className="text-[9px] text-gray-500 tracking-[0.4em] uppercase font-bold">Autonomous Medical Intelligence</p>
            </div>
          </div>
          <div className="hidden md:flex gap-6 items-center">
             {[1, 2, 3].map((s) => (
               <div key={s} className="flex flex-col items-center group cursor-pointer" onClick={() => s < step && setStep(s as AppStep)}>
                  <div className={`text-[10px] font-black tracking-widest transition-all duration-300 ${step === s ? 'neon-text' : 'text-gray-600'}`}>
                    0{s} {s === 1 ? 'PROFILE' : s === 2 ? 'LAB' : 'DIAGNOSIS'}
                  </div>
                  <div className={`h-0.5 mt-1 transition-all duration-500 ${step === s ? 'w-full bg-cyan-400 shadow-[0_0_10px_#00f3ff]' : 'w-0 bg-gray-800'}`}></div>
               </div>
             ))}
          </div>
        </div>
      </header>

      <main className="w-full max-w-4xl px-4 mt-12">
        {step === 1 && (
          <div className="glass rounded-[40px] p-12 space-y-12 animate-in slide-in-from-bottom duration-1000">
            <div className="space-y-3">
              <h2 className="text-3xl font-black flex items-center gap-4 neon-text font-poppins">
                <User className="w-8 h-8" /> PATIENT IDENTITY
              </h2>
              <p className="text-gray-500 text-sm max-w-md">Calibrating AGI logic using fundamental patient metrics for high-precision diagnostic matching.</p>
            </div>

            <div className="space-y-10">
              {/* Name */}
              <div className="space-y-4">
                <label className="text-[10px] uppercase tracking-[0.3em] font-black text-gray-600 ml-1">Entity Name</label>
                <input 
                  type="text"
                  placeholder="ID ENTITY: Enter Patient Name"
                  className="w-full input-glass rounded-2xl px-8 py-6 outline-none text-xl font-bold text-cyan-50 placeholder:opacity-20"
                  value={patient.name}
                  onChange={(e) => setPatient({...patient, name: e.target.value})}
                />
              </div>

              {/* Age - Smooth Reveal */}
              <div className={`smooth-reveal ${showAge ? 'active' : ''}`}>
                <div className="space-y-4 pt-4">
