                      >
                        {g.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {showNextStep1 && (
                <div className="pt-6 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                    <button 
                    onClick={() => setStep(2)}
                    className="w-full bg-cyan-600 hover:bg-cyan-500 text-black font-black text-lg py-7 rounded-2xl flex items-center justify-center gap-4 transition-all transform hover:scale-[1.01] active:scale-[0.98] shadow-[0_0_40px_rgba(0,243,255,0.3)]"
                    >
                    INITIALIZE LABORATORY <ChevronRight className="w-6 h-6" />
                    </button>
                </div>
              )}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-10 animate-in slide-in-from-right duration-1000">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Prescription Upload */}
              <div className="glass rounded-[35px] p-8 space-y-6 relative group border-t border-cyan-500/20">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black flex items-center gap-3 neon-text font-poppins italic">
                    <FileText className="w-5 h-5" /> PRESCRIPTIONS
                  </h3>
                  <label className="cursor-pointer p-3 glass rounded-full hover:bg-cyan-500/20 transition-all border border-cyan-400/30">
                    <Plus className="w-6 h-6 neon-text" />
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'prescription')} accept=".pdf,.jpg,.png,.doc,.docx" />
                  </label>
                </div>
                <div className="min-h-[160px] border border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center p-4 bg-white/[0.01] group-hover:bg-white/[0.03] transition-all overflow-y-auto max-h-[300px] scrollbar-hide">
                  {files.filter(f => f.type === 'prescription').length === 0 ? (
                    <div className="text-center space-y-2 opacity-20">
                      <FileText className="w-10 h-10 mx-auto" />
                      <p className="text-[10px] uppercase font-black tracking-widest">Awaiting Clinical Data</p>
                    </div>
                  ) : (
                    <div className="w-full space-y-3">
                      {files.filter(f => f.type === 'prescription').map(f => (
                        <div key={f.id} className="relative bg-white/[0.04] p-4 rounded-xl flex items-center justify-between animate-in slide-in-from-left duration-500">
                          <div className="flex flex-col">
                            <span className="text-[11px] font-bold text-gray-300">{f.name}</span>
                            {fileNotifications[f.id] && (
                               <div className="flex items-center gap-2 text-[9px] text-emerald-400 font-black animate-pulse mt-1">
                                 <Check className="w-3 h-3" /> UPLOAD SUCCESS
                               </div>
                            )}
                          </div>
                          <button onClick={() => removeFile(f.id)} className="p-2 hover:bg-red-500/20 rounded-lg transition-all text-gray-600 hover:text-red-400">
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Scan Reports Upload */}
              <div className="glass rounded-[35px] p-8 space-y-6 relative group border-t border-emerald-500/20">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black flex items-center gap-3 text-emerald-400 font-poppins italic">
                    <Activity className="w-5 h-5" /> SCANS
