                  <label className="cursor-pointer p-3 glass rounded-full hover:bg-emerald-500/20 transition-all border border-emerald-400/30">
                    <Plus className="w-6 h-6 text-emerald-400" />
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'scan')} accept=".pdf,.jpg,.png" />
                  </label>
                </div>
                <div className="min-h-[160px] border border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center p-4 bg-white/[0.01] group-hover:bg-white/[0.03] transition-all overflow-y-auto max-h-[300px] scrollbar-hide">
                  {files.filter(f => f.type === 'scan').length === 0 ? (
                    <div className="text-center space-y-2 opacity-20">
                      <Activity className="w-10 h-10 mx-auto" />
                      <p className="text-[10px] uppercase font-black tracking-widest">Awaiting Lab Biomarkers</p>
                    </div>
                  ) : (
                    <div className="w-full space-y-3">
                      {files.filter(f => f.type === 'scan').map(f => (
                        <div key={f.id} className="relative bg-white/[0.04] p-4 rounded-xl flex items-center justify-between animate-in slide-in-from-left duration-500">
                          <div className="flex flex-col">
                            <span className="text-[11px] font-bold text-gray-300">{f.name}</span>
                            {fileNotifications[f.id] && (
                               <div className="flex items-center gap-2 text-[9px] text-emerald-400 font-black animate-pulse mt-1">
                                 <Check className="w-3 h-3" /> UPLOAD SUCCESS
                               </div>
                            )}
                          </div>
                          <button onClick={() => removeFile(f.id)} className="p-2 hover:bg-red-500/20 rounded-lg transition-all text-gray-600 hover:text-red-400">
