                value={manualMeds}
                onChange={(e) => setManualMeds(e.target.value)}
              />
            </div>

            {/* Tablet Photos */}
            <div className="glass rounded-[35px] p-8 space-y-8 border-t border-cyan-500/20 relative overflow-hidden">
              <div className="flex justify-between items-center relative z-10">
                <h3 className="text-lg font-black flex items-center gap-3 neon-text font-poppins italic">
                  <Pill className="w-5 h-5" /> PHARMA IMAGING
                </h3>
                <label className="cursor-pointer flex items-center gap-3 px-6 py-3.5 glass rounded-full hover:bg-cyan-500/20 transition-all border border-cyan-400/30">
                  <Camera className="w-5 h-5 neon-text" />
                  <span className="text-[10px] font-black uppercase tracking-[0.2em]">Visual Input</span>
                  <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'tablet')} accept="image/*" />
