  const [files, setFiles] = useState<MedicalFile[]>([]);
  const [fileNotifications, setFileNotifications] = useState<Record<string, boolean>>({});
  const [tabletToast, setTabletToast] = useState(false);
  const [manualMeds, setManualMeds] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [webResults, setWebResults] = useState<string[]>([]);
  const [labVerified, setLabVerified] = useState(false);

  // Progressive reveal triggers
  const showAge = patient.name.trim().length > 2;
  const showGender = typeof patient.age === 'number' || (patient.age !== '' && parseInt(patient.age as string) > 0);
  const showNextStep1 = patient.gender !== '';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map(f => {
        const id = Math.random().toString(36).substr(2, 9);

        // General Notification
        setFileNotifications(prev => ({ ...prev, [id]: true }));
        setTimeout(() => {
          setFileNotifications(prev => ({ ...prev, [id]: false }));
        }, 5000);

        // Tablet specific Toast
        if (type === 'tablet') {
          setTabletToast(true);
          setTimeout(() => setTabletToast(false), 3000);
        }

        return {
          id,
          file: f,
          previewUrl: URL.createObjectURL(f),
          type,
          name: f.name
        };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
    setFileNotifications(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
  };

  const dismissNotification = (id: string) => {
    setFileNotifications(prev => ({ ...prev, [id]: false }));
  };

  const startAnalysis = async () => {
    if (files.length === 0 && manualMeds.trim().length === 0) {
      alert("Please upload medical documents or log medications for analysis.");
      return;
    }
    setIsAnalyzing(true);
    setStep(3);
    try {
      const result = await performMultiAIAnalysis(patient, files, manualMeds);
      setAnalysisResult(result);
      const searchTerms = result.diagnosis.map(d => d.issue).join(" ");
      const web = await webFetch(searchTerms);
      setWebResults(web);
    } catch (err) {
      console.error("Analysis failed", err);
      setAnalysisResult(MOCK_RESULT);
    } finally {
      setIsAnalyzing(false);
    }
