import React, { useState, useEffect, useMemo } from 'react';
import { 
  Brain, 
  Plus, 
  FileText, 
  Camera, 
  ChevronRight, 
  Loader2, 
  CheckCircle2, 
  AlertTriangle, 
  XCircle,
  Search,
  User,
  Layers,
  Trash2,
  Check,
  X,
  Dna,
  Heart,
  ShieldCheck,
  Zap,
  Leaf,
  Sun,
  Droplets,
  Moon,
  Smile,
  Shield,
  Activity,
  Microscope,
  Thermometer,
  ClipboardList,
  Fingerprint,
  Pill,
  Wine,
  Flame,
  Stethoscope,
  ChevronDown,
  Info
} from 'lucide-react';
import { PatientInfo, MedicalFile, AppStep, AnalysisResult } from './types';
import { performMultiAIAnalysis, webFetch } from './services/putterAdapter';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(1);
  const [patient, setPatient] = useState<PatientInfo>({ 
    name: '', 
    age: '', 
    gender: '',
    habits: { smoking: false, alcohol: false } 
  });
  const [files, setFiles] = useState<MedicalFile[]>([]);
  const [fileNotifications, setFileNotifications] = useState<Record<string, boolean>>({});
  const [tabletToast, setTabletToast] = useState(false);
  const [manualMeds, setManualMeds] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [webResults, setWebResults] = useState<string[]>([]);
  const [labVerified, setLabVerified] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  // Scroll detection for header animation
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Progressive validation
  const canProceedStep1 = useMemo(() => {
    return patient.name.trim().length >= 2 && patient.age !== '' && patient.gender !== '';
  }, [patient]);

  const detectScanType = (filename: string): MedicalFile['detectedType'] => {
    const name = filename.toLowerCase();
    if (name.includes('xray') || name.includes('x-ray') || name.includes('chest')) return 'xray';
    if (name.includes('mri') || name.includes('brain') || name.includes('scan')) return 'mri';
    if (name.includes('blood') || name.includes('test') || name.includes('cbc') || name.includes('lab')) return 'blood';
    if (name.includes('ct') || name.includes('tomography')) return 'ct';
    return 'generic';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map(f => {
        const id = Math.random().toString(36).substr(2, 9);

        setFileNotifications(prev => ({ ...prev, [id]: true }));
        setTimeout(() => setFileNotifications(prev => ({ ...prev, [id]: false })), 5000);

        if (type === 'tablet') {
          setTabletToast(true);
          setTimeout(() => setTabletToast(false), 3000);
        }

        return {
          id,
          file: f,
          previewUrl: URL.createObjectURL(f),
          type,
          name: f.name,
          detectedType: type === 'scan' ? detectScanType(f.name) : undefined
        };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const updateFileCategory = (id: string, category: MedicalFile['detectedType']) => {
    setFiles(prev => prev.map(f => f.id === id ? { ...f, detectedType: category } : f));
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setStep(3);
