    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const canProceedStep1 = useMemo(() => {
    return patient.name.trim().length >= 2 && patient.age !== '' && patient.gender !== '';
  }, [patient]);

  const detectScanType = (filename: string): MedicalFile['detectedType'] => {
    const name = filename.toLowerCase();
    if (name.includes('xray') || name.includes('x-ray') || name.includes('chest')) return 'xray';
    if (name.includes('mri') || name.includes('brain') || name.includes('scan')) return 'mri';
    if (name.includes('blood') || name.includes('test') || name.includes('cbc') || name.includes('lab')) return 'blood';
    if (name.includes('ct') || name.includes('tomography')) return 'ct';
    return 'generic';
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const selectedFiles = Array.from(e.target.files);

      for (const f of selectedFiles) {
        const id = Math.random().toString(36).substr(2, 9);

        // Size validation
        if (f.size > 10 * 1024 * 1024) {
          setFileErrors(prev => ({ ...prev, [id]: "File exceeds 10MB limit." }));
        }

        const newFile: MedicalFile = {
          id,
          file: f,
          previewUrl: URL.createObjectURL(f),
          type,
          name: f.name,
          detectedType: type === 'scan' ? detectScanType(f.name) : undefined
        };

        setFiles(prev => [...prev, newFile]);

        if (type === 'tablet') {
          setTabletToast(true);
          setTimeout(() => setTabletToast(false), 3000);
        }
      }
    }
    // Reset input
    e.target.value = '';
  };

  const retryFileUpload = (id: string) => {
    setFileErrors(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    // In a real app, we'd trigger a re-processing or re-upload here.
    // For now, we clear the error to simulate success.
  };

  const updateFileCategory = (id: string, category: MedicalFile['detectedType']) => {
    setFiles(prev => prev.map(f => f.id === id ? { ...f, detectedType: category } : f));
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
    setFileErrors(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
  };

