            <div className={`p-3 rounded-2xl bg-cyan-500/10 neon-border transition-all duration-500 ${isScrolled ? 'scale-90' : 'scale-110'}`}>
              <Stethoscope className="w-7 h-7 neon-text" />
            </div>
            <div>
              <h1 className={`font-black tracking-tight neon-text font-poppins italic transition-all duration-500 ${isScrolled ? 'text-xl' : 'text-2xl'}`}>Vayu AGI</h1>
