                  <button onClick={() => setStep(2)} disabled={!patient.gender} className={`w-full font-black text-md md:text-xl py-6 md:py-10 rounded-2xl md:rounded-[40px] flex items-center justify-center gap-4 tracking-widest uppercase transition-all ${patient.gender ? 'bg-emerald-600 text-black shadow-lg' : 'bg-gray-900 text-gray-800 opacity-40 cursor-not-allowed'}`}>
