                      <span className="text-6xl md:text-8xl font-black neon-text italic tracking-tighter">{analysisResult.confidenceScore}<span className="text-xl ml-1 opacity-20">%</span></span>
                   </div>
                   <div className="glass p-8 md:p-12 rounded-[40px] flex flex-col items-center justify-center gap-4">
                        {analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? <AlertTriangle className="w-10 h-10 text-red-500 animate-pulse" /> : <ShieldCheck className="w-10 h-10 text-emerald-400" />}
                        <span className={`text-xl md:text-2xl font-black italic text-center uppercase tracking-tight ${analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? 'text-red-500' : 'text-emerald-400'}`}>
                            {analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? 'Attention Required' : 'Status Stable'}
                        </span>
                   </div>
                </div>

                <div className="space-y-8">
                  <h3 className="text-2xl font-black neon-text uppercase italic px-4">Observations</h3>
                  <div className="space-y-6">
                    {analysisResult.diagnosis.map((d, i) => (
                      <div key={i} className="glass rounded-[35px] p-6 md:p-10 border-l-[6px] md:border-l-[12px] border-l-cyan-500 hover:bg-white/5 transition-all">
                        <div className="flex flex-col md:flex-row justify-between md:items-center gap-4 mb-8">
                          <h4 className="text-xl md:text-3xl font-black italic uppercase tracking-tight">{d.issue}</h4>
                          <span className={`px-5 py-2 rounded-full text-[8px] md:text-[10px] font-black tracking-widest border self-start ${d.severity === 'CRITICAL' ? 'bg-red-500/10 border-red-500/40 text-red-400' : 'bg-emerald-500/10 border-emerald-400/40 text-emerald-400'}`}>{d.severity}</span>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                          <div className="p-6 bg-black/30 rounded-2xl border border-white/5">
                            <p className="text-[9px] text-gray-600 font-black uppercase mb-2">Reading</p>
                            <p className="text-xl md:text-2xl font-black neon-text">{d.values}</p>
                          </div>
                          <div className="p-6 bg-black/30 rounded-2xl border border-white/5">
                            <p className="text-[9px] text-gray-600 font-black uppercase mb-2">Baseline</p>
                            <p className="text-xl md:text-2xl font-black text-gray-500">{d.referenceRange}</p>
                          </div>
                        </div>
                        <p className="text-gray-400 text-sm md:text-lg font-bold leading-relaxed">{d.assessment}</p>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="space-y-8">
                    <h3 className="text-2xl font-black text-purple-400 uppercase italic px-4">Regimen</h3>
                    <div className="glass rounded-[35px] overflow-hidden border border-white/5">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead className="bg-white/5 text-[9px] font-black uppercase tracking-widest text-gray-600 border-b border-white/5">
                                    <tr>
                                        <th className="p-6">Compound</th>
                                        <th className="p-6">Cycle</th>
                                        <th className="p-6 text-right">Status</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/5">
                                    {analysisResult.prescriptions.map((p, i) => (
                                        <tr key={i} className="hover:bg-white/5">
                                            <td className="p-6">
                                                <div className="font-black text-lg md:text-xl italic uppercase truncate max-w-[120px] md:max-w-none">{p.name}</div>
                                                <div className="text-[8px] text-gray-500 font-bold mt-1">{p.dosage}</div>
                                            </td>
                                            <td className="p-6 text-[10px] text-gray-400 font-black uppercase">{p.frequency}</td>
                                            <td className="p-6 text-right">
                                                {p.verification === 'CORRECT' ? <CheckCircle2 className="w-6 h-6 text-emerald-500 inline" /> : <AlertTriangle className="w-6 h-6 text-yellow-500 inline" />}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <button onClick={() => window.print()} className="py-6 rounded-2xl glass text-[10px] font-black uppercase tracking-widest text-gray-500">Export PDF</button>
                    <button onClick={() => window.location.reload()} className="py-6 rounded-2xl bg-cyan-600 text-[10px] font-black uppercase tracking-widest text-black shadow-lg">Reset Protocol</button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <div className="fixed -top-40 -right-40 w-[600px] h-[600px] bg-cyan-600/5 rounded-full blur-[150px] -z-10 animate-pulse"></div>
    </div>
  );
};

