    { issue: "BP Elevation", values: "158/104 mmHg", severity: "CRITICAL", referenceRange: "120/80", assessment: "Consistent hypertensive force within system. Requires immediate modulation." },
    { issue: "Blood Glucose", values: "135 mg/dL", severity: "MODERATE", referenceRange: "70-99", assessment: "Glycemic markers trending above thresholds. Nutritional intervention advised." }
  ],
  prescriptions: [
