    { name: "GlucoGuard", dosage: "500mg", frequency: "Twice Daily", verification: "CHECK", verificationNote: "Monitor tolerance." }
  ],
  recommendations: { do: ["Activity", "Low sodium"], avoid: ["Stimulants"], monitor: ["Daily BP"], consult: "Consult within 48h." },
  confidenceScore: 98
};

