import React, { useState, useEffect, useMemo } from 'react';
import { 
  Brain, 
  Plus, 
  FileText, 
  Camera, 
  ChevronRight, 
  Loader2, 
  CheckCircle2, 
  AlertTriangle, 
  XCircle,
  Search,
  User,
  Layers,
  Trash2,
  Check,
  X,
  Dna,
  Heart,
  ShieldCheck,
  Zap,
  Leaf,
  Sun,
  Droplets,
  Moon,
  Smile,
  Shield,
  Activity,
  Microscope,
  Thermometer,
  ClipboardList,
  Fingerprint,
  Pill,
  Wine,
  Flame,
  Stethoscope,
  ChevronDown,
  Info,
  RefreshCw,
  Edit3,
  ArrowRight,
  Globe
} from 'lucide-react';
import { PatientInfo, MedicalFile, AppStep, AnalysisResult } from './types';
import { performMultiAIAnalysis, webFetch } from './services/putterAdapter';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(1);
  const [regSubStep, setRegSubStep] = useState<'name' | 'age' | 'gender'>('name');
  const [patient, setPatient] = useState<PatientInfo>({ 
    name: '', 
    age: '', 
    gender: '',
    habits: { smoking: false, alcohol: false } 
  });

  const [files, setFiles] = useState<MedicalFile[]>([]);
  const [fileErrors, setFileErrors] = useState<Record<string, string>>({});
  const [tabletToast, setTabletToast] = useState(false);
  const [manualMeds, setManualMeds] = useState('');
  const [manualTablets, setManualTablets] = useState<string[]>([]);
  const [currentTabletInput, setCurrentTabletInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [webResults, setWebResults] = useState<string[]>([]);
  const [labVerified, setLabVerified] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  const ageValidation = useMemo(() => {
    const ageStr = patient.age.toString();
    if (ageStr === '') return { isValid: false, error: null };
    const num = parseInt(ageStr);
    if (isNaN(num) || num <= 0 || num > 120) {
      return { isValid: false, error: "Age must be between 1 and 120." };
    }
    return { isValid: true, error: null };
  }, [patient.age]);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 15);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>, type: MedicalFile['type']) => {
    if (e.target.files) {
      const selectedFiles = Array.from(e.target.files);
      const newFiles: MedicalFile[] = [];
      const newErrors: Record<string, string> = { ...fileErrors };
      for (const f of selectedFiles) {
        const id = Math.random().toString(36).substr(2, 9);
        if (f.size > 10 * 1024 * 1024) newErrors[id] = "File exceeds 10MB limit.";
        newFiles.push({ id, file: f, previewUrl: URL.createObjectURL(f), type, name: f.name });
        if (type === 'tablet') {
          setTabletToast(true);
          setTimeout(() => setTabletToast(false), 3000);
        }
      }
      setFiles(prev => [...prev, ...newFiles]);
      setFileErrors(newErrors);
    }
    e.target.value = '';
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const addManualTablet = () => {
    if (currentTabletInput.trim()) {
      setManualTablets(prev => [...prev, currentTabletInput.trim()]);
      setCurrentTabletInput('');
    }
  };

  const startAnalysis = async () => {
    setIsAnalyzing(true);
    setStep(3);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    const fullMedContext = `${manualMeds}\nManual Tablets: ${manualTablets.join(', ')}`;
    try {
      const result = await performMultiAIAnalysis(patient, files, fullMedContext);
      setAnalysisResult(result);

      // Use Putter.js webFetch mock
      const webInfo = await webFetch(result.diagnosis[0]?.issue || "general health");
      setWebResults(webInfo);
    } catch (err) {
      setAnalysisResult(MOCK_RESULT);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const DnaLoader = () => (
    <div className="relative w-24 h-32 flex items-center justify-center">
      {[...Array(8)].map((_, i) => (
        <React.Fragment key={i}>
          <div className="dna-node" style={{ left: `${i * 12}%`, animationDelay: `${i * 0.1}s`, background: '#00f3ff' }} />
          <div className="dna-node" style={{ left: `${i * 12}%`, animationDelay: `${i * 0.1 + 1.25}s`, background: '#a855f7' }} />
        </React.Fragment>
      ))}
      <div className="absolute neon-border p-4 rounded-full bg-cyan-900/10 backdrop-blur-md">
        <Dna className="w-6 h-6 neon-text animate-pulse" />
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-white flex flex-col items-center pb-8 overflow-x-hidden relative">
      {/* Pharma Toast */}
      {tabletToast && (
        <div className="fixed top-20 z-[250] px-3 py-1.5 glass neon-border rounded-full flex items-center gap-2 animate-in fade-in slide-in-from-top-4 shadow-2xl mx-4">
          <Pill className="w-3 h-3 text-emerald-400" />
          <span className="text-[8px] font-black uppercase tracking-widest neon-text">Tablet Vector Registered</span>
        </div>
      )}

      {/* Header */}
      <header className={`w-full h-14 md:h-16 flex items-center justify-center fixed top-0 left-0 right-0 z-[200] transition-all duration-500 ${isScrolled ? 'header-active' : 'header-glass'}`}>
        <div className="w-full max-w-6xl px-6 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer group" onClick={() => { setStep(1); setRegSubStep('name'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>
            <div className={`p-1.5 rounded-lg bg-cyan-500/10 neon-border transition-all duration-500 ${isScrolled ? 'scale-90' : 'scale-105'}`}>
              <Stethoscope className="w-4 h-4 neon-text" />
            </div>
            <div>
              <h1 className={`font-black tracking-tight neon-text font-poppins italic transition-all duration-500 ${isScrolled ? 'text-sm' : 'text-base md:text-lg'}`}>Vayu AGI</h1>
              <p className="text-[5px] md:text-[6px] text-gray-600 tracking-[0.2em] uppercase font-bold">Quantum Medical Node</p>
            </div>
          </div>
          <div className="flex gap-4 md:gap-8">
            {[1, 2, 3].map((s) => (
              <div key={s} className={`flex flex-col items-center transition-all ${step === s ? 'opacity-100' : 'opacity-20'}`}>
                <span className="text-[7px] font-black tracking-widest uppercase">Protocol {s}</span>
                <div className={`h-[1px] mt-0.5 transition-all ${step === s ? 'w-full bg-cyan-400' : 'w-0'}`}></div>
              </div>
            ))}
          </div>
        </div>
      </header>

      <div className="h-14 md:h-16 w-full" />

      <main className="w-full max-w-5xl px-4 mt-6 md:mt-8 relative z-10">
        {step === 1 && (
          <div className="glass rounded-[20px] md:rounded-[40px] p-6 md:p-10 space-y-8 animate-in fade-in duration-500">
            <div className="space-y-1">
              <div className="flex items-center gap-2 text-cyan-400">
                <Brain className="w-5 h-5 animate-pulse" />
                <h2 className="text-lg md:text-2xl font-black font-poppins italic uppercase">Registration</h2>
              </div>
              <p className="text-gray-600 text-[9px] md:text-[10px] uppercase tracking-widest">Establishing biological equivalence parameters.</p>
            </div>

            <div className="space-y-8 md:space-y-12">
              <div className={`space-y-3 transition-all duration-500 ${regSubStep !== 'name' ? 'opacity-10 blur-sm scale-95' : ''}`}>
                <label className="text-[8px] uppercase tracking-[0.3em] font-black text-gray-500 flex items-center gap-2">
                  <Fingerprint className="w-2 h-2 text-cyan-500" /> System Identification
                </label>
                <p className="text-sm md:text-lg font-bold font-poppins">"Enter full legal name to begin synthesis."</p>
                <div className="flex flex-col md:flex-row gap-2">
                  <input type="text" autoFocus placeholder="Name" className="flex-1 input-glass rounded-xl px-5 py-4 md:py-5 outline-none text-base font-black uppercase" value={patient.name} onChange={(e) => setPatient({...patient, name: e.target.value})} disabled={regSubStep !== 'name'} />
                  {patient.name.trim().length >= 2 && regSubStep === 'name' && (
                    <button onClick={() => setRegSubStep('age')} className="py-4 px-6 bg-cyan-600 rounded-xl text-black hover:bg-cyan-500 transition-all flex items-center justify-center"><ArrowRight className="w-4 h-4" /></button>
                  )}
                </div>
              </div>

              {regSubStep !== 'name' && (
                <div className={`space-y-3 transition-all duration-700 animate-in fade-in slide-in-from-bottom-2 ${regSubStep !== 'age' ? 'opacity-10 blur-sm scale-95' : ''}`}>
                  <label className="text-[8px] uppercase tracking-[0.3em] font-black text-gray-500 flex items-center gap-2">
                    <Activity className="w-2 h-2 text-emerald-500" /> Temporal Check
                  </label>
                  <p className="text-sm md:text-lg font-bold font-poppins">"What is your biological age cycle?"</p>
                  <div className="flex flex-col md:flex-row gap-2">
                    <div className="flex-1">
