                      {['Male', 'Female', 'Other'].map((g) => (
                        <button key={g} onClick={() => setPatient({...patient, gender: g})} className={`rounded-lg border h-12 md:h-14 transition-all font-black text-[8px] tracking-widest uppercase flex items-center justify-center gap-1 ${patient.gender === g ? 'bg-cyan-500/20 border-cyan-400 text-cyan-400' : 'bg-white/5 border-white/5 text-gray-700'}`}>
