                        </button>
                      ))}
                    </div>
                  </div>
                  <button onClick={() => setStep(2)} disabled={!patient.gender} className={`w-full font-black text-[10px] py-4 md:py-6 rounded-xl md:rounded-[20px] flex items-center justify-center gap-2 tracking-[0.4em] uppercase transition-all ${patient.gender ? 'bg-emerald-600 text-black shadow-lg hover:scale-[1.01]' : 'bg-gray-900 text-gray-800 opacity-40 cursor-not-allowed'}`}>
                    Access Lab Terminal <Microscope className="w-4 h-4" />
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="glass rounded-[20px] md:rounded-[40px] p-6 md:p-10 space-y-8 animate-in fade-in duration-500">
            <div className="flex items-center justify-between border-b border-white/5 pb-4">
              <div className="space-y-1">
                <h2 className="text-lg md:text-2xl font-black neon-text uppercase italic">Laboratory Terminal</h2>
                <p className="text-gray-500 text-[8px] md:text-[9px] uppercase tracking-widest">Awaiting clinical evidence packets.</p>
              </div>
              <Activity className="w-6 h-6 md:w-8 md:h-8 neon-text animate-pulse" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Prescription Section */}
              <div className="glass rounded-[15px] p-4 border border-cyan-500/10">
                <div className="flex justify-between items-center mb-3">
                  <div className="flex items-center gap-2">
                    <FileText className="w-3 h-3 neon-text" />
                    <h3 className="text-[8px] font-black uppercase tracking-widest">Medical Records</h3>
                  </div>
                  <label className="cursor-pointer p-1.5 glass rounded-full hover:neon-border transition-all">
                    <Plus className="w-3 h-3 neon-text" />
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'prescription')} accept=".pdf,.jpg,.png" />
                  </label>
                </div>
                <div className="h-[80px] overflow-y-auto space-y-1 bg-black/40 rounded-lg p-2 text-[8px] scrollbar-hide">
                  {files.filter(f => f.type === 'prescription').length === 0 ? <p className="text-gray-800 text-center py-6 uppercase tracking-widest">No Documents</p> : files.filter(f => f.type === 'prescription').map(f => (
                    <div key={f.id} className="bg-white/5 p-1.5 rounded flex items-center justify-between border border-white/5">
                      <span className="truncate max-w-[120px] text-gray-400 font-bold">{f.name}</span>
                      <button onClick={() => removeFile(f.id)} className="text-red-900 hover:text-red-500 transition-colors"><Trash2 className="w-3 h-3" /></button>
                    </div>
                  ))}
                </div>
              </div>

              {/* Scan Section */}
              <div className="glass rounded-[15px] p-4 border border-emerald-500/10">
                <div className="flex justify-between items-center mb-3">
                  <div className="flex items-center gap-2">
                    <Layers className="w-3 h-3 text-emerald-400" />
                    <h3 className="text-[8px] font-black uppercase tracking-widest text-emerald-400">Imaging Scans</h3>
                  </div>
                  <label className="cursor-pointer p-1.5 glass rounded-full hover:border-emerald-500 transition-all">
                    <Plus className="w-3 h-3 text-emerald-400" />
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'scan')} accept=".pdf,.jpg,.png" />
                  </label>
                </div>
                <div className="h-[80px] overflow-y-auto space-y-1 bg-black/40 rounded-lg p-2 text-[8px] scrollbar-hide">
                  {files.filter(f => f.type === 'scan').length === 0 ? <p className="text-gray-800 text-center py-6 uppercase tracking-widest">No Imaging</p> : files.filter(f => f.type === 'scan').map(f => (
                    <div key={f.id} className="bg-white/5 p-1.5 rounded flex items-center justify-between border border-white/5">
                      <span className="truncate max-w-[120px] text-gray-400 font-bold">{f.name}</span>
                      <button onClick={() => removeFile(f.id)} className="text-red-900 hover:text-red-500"><Trash2 className="w-3 h-3" /></button>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Tablet Protocol Section */}
            <div className="glass rounded-[20px] p-5 border border-purple-500/10 space-y-4">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <Pill className="w-3.5 h-3.5 text-purple-400" />
                  <h3 className="text-[9px] font-black uppercase tracking-widest text-purple-400">Tablet Verification Protocol</h3>
                </div>
                <label className="cursor-pointer flex items-center gap-2 bg-purple-500/10 px-3 py-1.5 rounded-full hover:bg-purple-500/20 transition-all border border-purple-500/20">
                  <Camera className="w-3 h-3 text-purple-400" />
