                  <input type="file" multiple className="hidden" onChange={(e) => handleFileChange(e, 'tablet')} accept=".jpg,.png" />
                </label>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-3">
                  <div className="flex gap-2">
                    <input type="text" placeholder="Manual Med Entry" className="flex-1 input-glass rounded-lg px-3 py-2 text-[9px] outline-none font-bold placeholder:text-gray-800" value={currentTabletInput} onChange={(e) => setCurrentTabletInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addManualTablet()} />
