                <div className="col-span-2 flex items-center justify-center gap-2 bg-white/5 rounded-lg border border-white/5 px-3">
                   <ShieldCheck className={`w-4 h-4 transition-colors ${labVerified ? 'text-emerald-500' : 'text-gray-800'}`} />
                   <span className="text-[7px] font-black uppercase text-gray-500">Integrity Check</span>
                   <button onClick={() => setLabVerified(!labVerified)} className={`w-8 h-4 rounded-full border p-0.5 transition-all ${labVerified ? 'bg-emerald-500/20 border-emerald-500' : 'bg-white/5 border-white/10'}`}><div className={`w-2.5 h-2.5 rounded-full transition-all ${labVerified ? 'translate-x-4 bg-white' : 'translate-x-0 bg-gray-700'}`}></div></button>
