            </div>

            <div className="flex flex-col md:flex-row gap-2">
              <button onClick={() => setStep(1)} className="py-4 px-8 glass text-[8px] font-black uppercase tracking-widest text-gray-600 order-2 md:order-1 hover:text-white transition-all">Phase 01</button>
              <button onClick={startAnalysis} disabled={!labVerified} className={`flex-1 py-4 rounded-xl font-black text-[10px] tracking-[0.4em] uppercase flex items-center justify-center gap-2 transition-all order-1 md:order-2 ${!labVerified ? 'bg-gray-900 text-gray-800 opacity-20 cursor-not-allowed' : 'bg-cyan-600 text-black shadow-lg hover:scale-[1.01]'}`}>Initialize Deep Synthesis <Brain className="w-4 h-4" /></button>
            </div>
