        )}

        {step === 3 && (
          <div className="space-y-8 animate-in fade-in duration-1000">
            {isAnalyzing ? (
              <div className="glass rounded-[30px] p-16 md:p-32 flex flex-col items-center justify-center space-y-8 shadow-2xl">
                <DnaLoader />
                <div className="text-center space-y-1">
                  <h2 className="text-lg md:text-2xl font-black neon-text uppercase italic tracking-[0.2em]">Processing Vayu Engine</h2>
                  <p className="text-[7px] uppercase tracking-[0.4em] font-black text-gray-700">Multi-Vector Analysis active</p>
                </div>
              </div>
            ) : analysisResult && (
              <div className="space-y-8 pb-16">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <div className="glass p-6 rounded-[25px] flex flex-col items-center justify-center gap-1 bg-cyan-400/[0.01]">
                      <span className="text-[7px] font-black text-gray-600 uppercase tracking-widest">Statistical Confidence</span>
                      <span className="text-4xl md:text-5xl font-black neon-text italic tracking-tighter">{analysisResult.confidenceScore}<span className="text-base ml-0.5 opacity-20">%</span></span>
                   </div>
                   <div className="glass p-6 rounded-[25px] flex flex-col items-center justify-center gap-2">
                        {analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? <AlertTriangle className="w-6 h-6 text-red-500 animate-pulse" /> : <ShieldCheck className="w-6 h-6 text-emerald-500" />}
                        <span className={`text-base md:text-lg font-black italic text-center uppercase tracking-tight ${analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? 'text-red-500' : 'text-emerald-400'}`}>
                            {analysisResult.diagnosis.some(d => d.severity === 'CRITICAL') ? 'Intervention Mandatory' : 'Equilibrium Stable'}
                        </span>
                   </div>
                </div>

                {/* Point-wise Summary Section */}
                <div className="space-y-4">
                  <h3 className="text-sm md:text-lg font-black neon-text uppercase italic px-4 flex items-center gap-2">
                    <ClipboardList className="w-4 h-4" /> Diagnosis Summary
                  </h3>
                  <div className="space-y-3">
                    {analysisResult.diagnosis.map((d, i) => (
                      <div key={i} className="glass rounded-[20px] p-5 border-l-[4px] border-l-cyan-500 hover:bg-white/5 transition-all">
                        <div className="flex flex-col md:flex-row justify-between md:items-center gap-2 mb-4">
                          <h4 className="text-sm md:text-base font-black italic uppercase tracking-tight">{d.issue}</h4>
                          <span className={`px-3 py-1 rounded-full text-[6px] md:text-[7px] font-black tracking-widest border self-start ${d.severity === 'CRITICAL' ? 'bg-red-500/10 border-red-500/40 text-red-400' : 'bg-emerald-500/10 border-emerald-400/40 text-emerald-400'}`}>{d.severity}</span>
                        </div>
                        <div className="grid grid-cols-2 gap-2 mb-4">
                          <div className="p-3 bg-black/40 rounded-lg border border-white/5">
                            <p className="text-[7px] text-gray-600 font-black uppercase mb-1">Detected Vector</p>
                            <p className="text-sm font-black neon-text">{d.values}</p>
                          </div>
                          <div className="p-3 bg-black/40 rounded-lg border border-white/5">
                            <p className="text-[7px] text-gray-600 font-black uppercase mb-1">Clinical Optimal</p>
                            <p className="text-sm font-black text-gray-500">{d.referenceRange}</p>
                          </div>
                        </div>
                        <p className="text-gray-400 text-[10px] font-medium leading-relaxed">{d.assessment}</p>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Table for Medications */}
                <div className="space-y-4">
                    <h3 className="text-sm md:text-lg font-black text-purple-400 uppercase italic px-4 flex items-center gap-2">
                        <Pill className="w-4 h-4" /> Regimen Synthesis
                    </h3>
                    <div className="glass rounded-[20px] overflow-hidden border border-white/5">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead className="bg-white/5 text-[7px] font-black uppercase tracking-widest text-gray-600 border-b border-white/5">
                                    <tr>
                                        <th className="p-4">Active Compound</th>
                                        <th className="p-4">Protocol Cycle</th>
                                        <th className="p-4 text-right">Verification</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/5 text-[9px]">
                                    {analysisResult.prescriptions.map((p, i) => (
                                        <tr key={i} className="hover:bg-white/5 transition-colors">
                                            <td className="p-4">
                                                <div className="font-black text-xs italic uppercase text-gray-200">{p.name}</div>
                                                <div className="text-[6px] text-gray-600 font-bold mt-0.5 uppercase tracking-tighter">{p.dosage}</div>
                                            </td>
                                            <td className="p-4 text-[8px] text-gray-400 font-black uppercase tracking-widest">{p.frequency}</td>
                                            <td className="p-4 text-right">
                                                {p.verification === 'CORRECT' ? <CheckCircle2 className="w-4 h-4 text-emerald-500 inline" /> : <AlertTriangle className="w-4 h-4 text-yellow-500 inline" />}
                                                <div className="text-[5px] text-gray-700 mt-1 uppercase tracking-tighter">{p.verificationNote}</div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                {/* Web Results Section using Putter adapter */}
                <div className="space-y-4">
                    <h3 className="text-sm md:text-lg font-black text-emerald-400 uppercase italic px-4 flex items-center gap-2">
                        <Globe className="w-4 h-4" /> Web Evidence Integration
                    </h3>
                    <div className="grid grid-cols-1 gap-3">
                        {webResults.map((res, i) => (
                            <div key={i} className="glass p-4 rounded-xl border border-emerald-500/10 flex items-start gap-3 bg-emerald-500/[0.01]">
                                <Info className="w-3 h-3 text-emerald-500 mt-0.5" />
                                <p className="text-[9px] font-bold text-gray-400 italic leading-relaxed">{res}</p>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3 mt-8">
                    <button onClick={() => window.print()} className="py-4 rounded-xl glass text-[8px] font-black uppercase tracking-[0.4em] text-gray-600 hover:text-white transition-all">Export Clinical Report</button>
                    <button onClick={() => window.location.reload()} className="py-4 rounded-xl bg-cyan-600 text-[8px] font-black uppercase tracking-[0.4em] text-black shadow-lg hover:bg-cyan-500 transition-all">Initialize New Cycle</button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <div className="fixed -top-40 -right-40 w-[600px] h-[600px] bg-cyan-600/5 rounded-full blur-[150px] -z-10 animate-pulse"></div>
      <div className="fixed -bottom-40 -left-40 w-[600px] h-[600px] bg-emerald-600/5 rounded-full blur-[150px] -z-10 animate-pulse"></div>
    </div>
  );
};

