          <div className="dna-node" style={{ left: `${i * 8}%`, animationDelay: `${i * 0.1 + 1.25}s`, background: '#a855f7' }} />
        </React.Fragment>
      ))}
      <div className="absolute neon-border p-5 rounded-full bg-cyan-900/10 backdrop-blur-md">
